-- Migration 0025: seed de receitas Nordeste (gerado por scripts/generate-recipes-seed.mjs)
-- 90 receitas curadas para region='nordeste' (10 por estado: AL, BA, CE, MA, PB, PE, PI, RN, SE). UPSERT por slug.

delete from public.recipes where region = 'nordeste';

on conflict (slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  category = excluded.category,
  time_label = excluded.time_label,
  description = excluded.description,
  region = excluded.region,
  state = excluded.state,
  data = excluded.data;
