insert into public.recipes (slug, title, icon, category, time_label, description, region, state, data) values
  ('carne_de_sol_grelhada', 'Carne de Sol Grelhada', '🥩', 'Almoço · Sertanejo', '25 min', 'Carne de sol grelhada na manteiga de garrafa — sabor sertanejo puro.', 'nordeste', 'CE', '{"ings":[{"n":"Carne de sol dessalgada em tiras","a":"300 g"},{"n":"Manteiga de garrafa","a":"2 col sopa"},{"n":"Alho e cebola","a":"a gosto"},{"n":"Cheiro-verde, pimenta-do-reino","a":"a gosto"}],"steps":["Dessalgue a carne em água fria por 1h (troque 2x).","Seque bem em papel-toalha antes de grelhar.","Derreta a manteiga numa frigideira bem quente.","Sele a carne por 2 min cada lado; reserve.","Na mesma frigideira, doure alho e cebola; devolva a carne.","Finalize com cheiro-verde e pimenta."],"tip":"Dessalga mal feita deixa o prato salgado demais — nunca pule a troca de águas."}'::jsonb),
  ('peixe_assado_nordestino', 'Peixe Assado Nordestino', '🐟', 'Jantar · Leve', '35 min', 'Pescada ou tambaqui assado com limão e coentro — simples e saboroso.', 'nordeste', 'BA', '{"ings":[{"n":"Postas de pescada ou tambaqui","a":"300 g"},{"n":"Limão, alho, coentro","a":"a gosto"},{"n":"Azeite de dendê (opcional)","a":"1 col sopa"},{"n":"Cebola em rodelas, pimentão","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, sal e coentro; deixe 15 min.","Disponha numa assadeira com cebola e pimentão em tiras.","Regue com azeite de dendê se for baiano.","Asse a 200 °C por 25 min, regando com o próprio caldo.","Sirva com arroz branco e salada."],"tip":"Peixe frio não pega tempero — deixe em temperatura ambiente por 10 min antes do forno."}'::jsonb),
  ('peixe_grelhado_simples', 'Peixe Grelhado Simples', '🐟', 'Jantar · Fit', '15 min', 'Filé de peixe grelhado rapidamente na chapa com limão.', 'nordeste', 'CE', '{"ings":[{"n":"Filé de peixe firme (tilápia/pescada)","a":"300 g"},{"n":"Limão, alho, azeite","a":"a gosto"},{"n":"Sal, pimenta, cheiro-verde","a":"a gosto"}],"steps":["Tempere os filés com limão, sal, pimenta e alho; deixe 10 min.","Seque bem antes de grelhar.","Grelhe 3 min cada lado em chapa bem quente com fio de azeite.","Sirva com limão fresco e cheiro-verde."],"tip":"Não mova o peixe enquanto grelha — espere formar a crosta dourada."}'::jsonb),
  ('arrumadinho_light', 'Arrumadinho Light', '🥗', 'Jantar · Leve', '20 min', 'Montagem fria de carne seca, feijão verde e vinagrete — sem farofa, fica mais leve.', 'nordeste', 'CE', '{"ings":[{"n":"Carne seca dessalgada e desfiada","a":"200 g"},{"n":"Feijão verde cozido","a":"1 xícara"},{"n":"Tomate, cebola, pimentão picados","a":"1 xícara"},{"n":"Coentro, vinagre, limão, azeite","a":"a gosto"}],"steps":["Refogue a carne seca desfiada com cebola por 5 min.","Prepare o vinagrete: tomate, cebola, pimentão, coentro, vinagre, limão.","Num prato, monte em camadas: feijão verde, carne seca, vinagrete.","Finalize com fio de azeite."],"tip":"Versão tradicional leva farofa por cima — omitir reduz muito as calorias sem perder graça."}'::jsonb),
  ('arrumadinho_tradicional', 'Arrumadinho Tradicional', '🥘', 'Almoço · Nordestino', '30 min', 'Carne seca refogada, feijão verde, vinagrete e farofa em camadas — clássico do sertão.', 'nordeste', 'CE', '{"ings":[{"n":"Carne seca dessalgada e desfiada","a":"250 g"},{"n":"Feijão verde cozido","a":"1,5 xícaras"},{"n":"Farofa de farinha de mandioca","a":"1 xícara"},{"n":"Tomate, cebola, pimentão, coentro","a":"a gosto"},{"n":"Manteiga de garrafa, azeite, limão","a":"a gosto"}],"steps":["Dessalgue e cozinhe a carne; desfie e refogue na manteiga com cebola.","Prepare o vinagrete cortando tudo em cubos pequenos.","Faça a farofa: manteiga + cebola + farinha, mexa até crocante.","Monte em camadas no prato: feijão, carne, vinagrete, farofa por cima.","Sirva morno ou em temperatura ambiente."],"tip":"Arrumadinho autêntico tem cada camada bem separada — não misture antes de servir."}'::jsonb),
  ('baiao_de_dois', 'Baião de Dois', '🍚', 'Almoço · Nordestino', '40 min', 'Arroz e feijão-verde cozidos juntos com queijo coalho e carne seca — ícone cearense.', 'nordeste', 'CE', '{"ings":[{"n":"Feijão verde cozido","a":"1,5 xícaras"},{"n":"Arroz cru","a":"1 xícara"},{"n":"Queijo coalho em cubos","a":"150 g"},{"n":"Carne seca ou paio em cubinhos","a":"100 g"},{"n":"Cebola, alho, cheiro-verde, manteiga de garrafa","a":"a gosto"}],"steps":["Doure a carne seca em cubos; reserve.","Refogue cebola e alho na manteiga; junte o arroz.","Acrescente o feijão verde com um pouco do caldo.","Cubra com água quente e cozinhe por 15 min.","Nos últimos 3 min, adicione queijo coalho e carne seca.","Finalize com cheiro-verde."],"tip":"Queijo coalho entra no fim — se for antes, derrete demais e perde a textura."}'::jsonb),
  ('camarao_grelhado_alho_integral', 'Camarão Grelhado ao Alho c/ Arroz Integral', '🦐', 'Almoço · Nordestino fit', '18 min', 'Camarão grelhado ao alho com arroz integral e vinagrete — sabor nordestino sem leite de coco nem dendê.', 'nordeste', 'BA', '{"ings":[{"n":"Camarão grande limpo","a":"130 g"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Tomate, cebola roxa, pimentão (vinagrete)","a":"a gosto"},{"n":"Folhas verdes (acompanhamento)","a":"à vontade"},{"n":"Alho, limão, coentro, azeite","a":"a gosto"}],"steps":["Tempere o camarão com limão, alho, sal; 10 min.","Aqueça frigideira com fio de azeite; grelhe o camarão por 2-3 min cada lado.","Finalize o camarão com coentro fresco.","Prepare o vinagrete: tomate, cebola roxa e pimentão picados com limão e azeite.","Sirva camarão sobre arroz integral, vinagrete e folhas ao lado."],"tip":"Camarão grelhado em vez de ensopado no dendê corta ~200kcal sem perder o sabor nordestino."}'::jsonb),
  ('bode_assado_sertao', 'Bode Assado ao Sertão', '🍖', 'Almoço · Sertanejo', '2h', 'Bode assado marinado com temperos sertanejos, acompanha farofa de cuscuz.', 'nordeste', 'PE', '{"ings":[{"n":"Pedaços de bode (pernil/paleta)","a":"800 g"},{"n":"Alho, cebola, limão, vinho tinto","a":"a gosto"},{"n":"Louro, cominho, pimenta-do-reino","a":"a gosto"},{"n":"Farofa de cuscuz pronta","a":"2 xícaras"}],"steps":["Tempere o bode com alho socado, sal, vinho e limão; deixe marinar 2h.","Acrescente cominho, louro e pimenta.","Asse em forno a 180 °C coberto por 1h30.","Destampe e doure nos últimos 20 min.","Sirva com a farofa de cuscuz ao lado."],"tip":"Bode tem cheiro forte — vinho e limão neutralizam. Use marinade generoso."}'::jsonb),
  ('caldinho_feijao', 'Caldinho de Feijão com Bacon', '🥣', 'Jantar · Aperitivo', '25 min', 'Caldo encorpado de feijão batido com bacon crocante por cima.', 'nordeste', 'PB', '{"ings":[{"n":"Feijão carioca cozido","a":"2 xícaras"},{"n":"Bacon em cubinhos","a":"80 g"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"},{"n":"Caldo de feijão reservado","a":"500 ml"},{"n":"Pimenta-do-reino, sal","a":"a gosto"}],"steps":["Bata o feijão com caldo no liquidificador até ficar liso.","Frite o bacon em cubinhos até dourar; reserve metade.","Na gordura do bacon, refogue cebola e alho.","Acrescente o feijão batido; cozinhe por 10 min.","Sirva com bacon reservado e cheiro-verde por cima."],"tip":"Coe o feijão batido antes de levar ao fogo se quiser caldo mais sedoso."}'::jsonb),
  ('canja_galinha_ne', 'Canja de Galinha Nordestina', '🍲', 'Jantar · Reconfortante', '45 min', 'Caldo leve de galinha com arroz e legumes — versão nordestina simples.', 'nordeste', 'BA', '{"ings":[{"n":"Peito de galinha com osso","a":"300 g"},{"n":"Arroz cru","a":"1/3 xícara"},{"n":"Cenoura e chuchu em cubinhos","a":"2 xícaras"},{"n":"Cebola, alho, louro, cheiro-verde","a":"a gosto"}],"steps":["Cozinhe a galinha com cebola, alho e louro em 1,5 l de água por 30 min.","Retire a galinha, desfie e reserve o caldo.","Ferva o caldo; adicione arroz e cozinhe por 8 min.","Junte os legumes e cozinhe mais 10 min.","Devolva a galinha à panela; aqueça.","Finalize com cheiro-verde."],"tip":"Caldo coado fica mais clean — deixe ossos e restinhos no coador."}'::jsonb),
  ('cuscuz_recheado', 'Cuscuz Recheado', '🌽', 'Almoço · Nordestino', '30 min', 'Cuscuz de milho recheado com queijo coalho e carne de sol — versão completa.', 'nordeste', 'CE', '{"ings":[{"n":"Flocão de milho","a":"2 xícaras"},{"n":"Água morna com sal","a":"1 xícara"},{"n":"Carne de sol desfiada refogada","a":"200 g"},{"n":"Queijo coalho em cubos","a":"150 g"},{"n":"Manteiga de garrafa, cebolinha","a":"a gosto"}],"steps":["Hidrate o flocão com água e sal por 5 min, mexendo.","Cozinhe no vapor (cuscuzeira) por 10 min.","Desenforme e abra ao meio como um sanduíche.","Recheie com carne de sol refogada e queijo coalho.","Feche, regue com manteiga de garrafa e finalize com cebolinha."],"tip":"Flocão hidratado demais vira pasta; menos, não cozinha. Proporção 2:1 é ideal."}'::jsonb),
  ('escondidinho_carne_sol', 'Escondidinho de Carne de Sol', '🥧', 'Almoço · Nordestino', '1h', 'Carne de sol escondida sob camada de purê de macaxeira gratinado.', 'nordeste', 'AL', '{"ings":[{"n":"Macaxeira (mandioca) cozida","a":"600 g"},{"n":"Carne de sol refogada e desfiada","a":"300 g"},{"n":"Requeijão ou catupiry","a":"200 g"},{"n":"Leite, manteiga, queijo ralado","a":"a gosto"}],"steps":["Amasse a macaxeira com leite e manteiga até virar purê liso.","Refogue a carne de sol com cebola e alho; desfie.","Num refratário, coloque metade do purê, a carne, requeijão e o resto do purê.","Cubra com queijo ralado.","Leve ao forno a 200 °C por 20 min até gratinar."],"tip":"Macaxeira (raíz) é mais saborosa que a mandioca de supermercado — vale procurar."}'::jsonb),
  ('feijao_corda_pacoca', 'Feijão-de-Corda com Paçoca de Carne Seca', '🍛', 'Jantar · Sertanejo', '40 min', 'Feijão-de-corda cremoso servido com paçoca salgada de carne seca por cima.', 'nordeste', 'CE', '{"ings":[{"n":"Feijão-de-corda seco","a":"1 xícara"},{"n":"Carne seca dessalgada desfiada","a":"150 g"},{"n":"Farinha de mandioca torrada","a":"1/2 xícara"},{"n":"Cebola, alho, coentro, manteiga de garrafa","a":"a gosto"}],"steps":["Cozinhe o feijão-de-corda em pressão por 20 min; escorra parte do caldo.","Refogue cebola e alho na manteiga; junte o feijão.","Numa travessa, bata no pilão carne seca + farinha até virar paçoca.","Sirva o feijão com a paçoca por cima e coentro fresco."],"tip":"Paçoca salgada bem socada é seca — se amassar demais, vira creme."}'::jsonb),
  ('galinha_caipira_quiabo', 'Galinha Caipira com Quiabo', '🐔', 'Almoço · Tradicional', '1h30', 'Galinha caipira ensopada com quiabo e pirão de farinha.', 'nordeste', 'BA', '{"ings":[{"n":"Galinha caipira em pedaços","a":"1 kg"},{"n":"Quiabo em rodelas","a":"300 g"},{"n":"Cebola, alho, tomate, cheiro-verde","a":"a gosto"},{"n":"Colorau (urucum)","a":"1 col sopa"}],"steps":["Lave o quiabo com vinagre e limão para reduzir baba; seque.","Tempere e doure a galinha com colorau em panela de pressão.","Cubra com água e cozinhe 40 min.","Abra a pressão; adicione o quiabo e cozinhe por 8 min em panela aberta.","Ajuste sal e finalize com cheiro-verde."],"tip":"Quiabo cozido em panela aberta solta menos baba que em pressão."}'::jsonb),
  ('pescada_coentro_pirao_light', 'Pescada Grelhada ao Coentro c/ Pirão Leve', '🐟', 'Almoço · Nordestino fit', '20 min', 'Pescada grelhada ao coentro com pirão leve e quiabo refogado — peixe nordestino sem leite de coco.', 'nordeste', 'PE', '{"ings":[{"n":"Filé de pescada","a":"130 g"},{"n":"Pirão leve (caldo de peixe c/ farinha)","a":"2 col sopa"},{"n":"Quiabo em rodelas","a":"1 xícara"},{"n":"Folhas verdes (acompanhamento)","a":"à vontade"},{"n":"Coentro, alho, limão, azeite","a":"a gosto"}],"steps":["Tempere a pescada com limão, alho e sal; 10 min.","Grelhe em fio de azeite por 3 min cada lado.","Prepare o pirão: aqueça 1/2 xícara de caldo de peixe e acrescente 1 col sopa de farinha; mexa 3 min.","Em paralelo, refogue quiabo com alho por 4 min.","Monte o prato: pescada, pirão leve, quiabo e folhas."],"tip":"Pirão light usa só 1 col sopa de farinha — espessa sem virar mingau."}'::jsonb),
  ('peixe_molho_tomate_feijao_verde', 'Peixe Branco ao Molho de Tomate c/ Feijão-Verde', '🐟', 'Almoço · Nordestino fit', '20 min', 'Peixe branco grelhado ao molho de tomate caseiro com feijão-verde — versão leve sem leite de coco.', 'nordeste', 'BA', '{"ings":[{"n":"Filé de pescada ou tilápia","a":"130 g"},{"n":"Molho de tomate caseiro","a":"1/2 xícara"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Feijão-verde cozido","a":"3 col sopa"},{"n":"Salada verde","a":"à vontade"},{"n":"Cebola, alho, coentro, limão","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, sal; 10 min.","Grelhe em fio de azeite por 3 min cada lado.","Em paralelo, aqueça o molho de tomate com cebola e alho por 5 min.","Aqueça feijão-verde e arroz integral.","Monte: peixe com molho de tomate por cima, arroz e feijão-verde ao lado."],"tip":"Feijão-verde é mais leve e tem sabor mais suave que o carioca — combina com peixe."}'::jsonb),
  ('peixe_tomate_jantar', 'Peixe ao Tomate c/ Feijão-Verde (Jantar)', '🐠', 'Jantar · Fit', '15 min', 'Peixe branco grelhado ao tomate com arroz integral e feijão-verde — jantar nordestino leve, sem leite de coco.', 'nordeste', 'BA', '{"ings":[{"n":"Filé de peixe branco","a":"120 g"},{"n":"Molho de tomate caseiro","a":"1/2 xícara"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Feijão-verde (ou carioca) cozido","a":"2 col sopa"},{"n":"Salada verde c/ tomate","a":"à vontade"},{"n":"Alho, coentro, limão","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho e sal; 10 min.","Grelhe em fio de azeite por 3 min cada lado.","Aqueça o molho de tomate com coentro.","Monte o prato: peixe com molho, arroz integral, feijão-verde e salada."],"tip":"Use molho de tomate pronto caseiro do freezer — o jantar fica em 15 min."}'::jsonb),
  ('omelete_queijo_coalho', 'Omelete com Queijo Coalho', '🍳', 'Jantar · Rápido', '10 min', 'Omelete rústico com cubos de queijo coalho — jantar simples e gostoso.', 'nordeste', 'CE', '{"ings":[{"n":"Ovos caipiras","a":"3 unidades"},{"n":"Queijo coalho em cubos","a":"80 g"},{"n":"Cebolinha, manteiga, sal, pimenta","a":"a gosto"}],"steps":["Bata os ovos com sal, pimenta e cebolinha.","Aqueça manteiga em frigideira antiaderente.","Despeje os ovos; quando firmar, adicione queijo coalho.","Dobre ao meio e cozinhe mais 1 min.","Sirva com salada."],"tip":"Queijo coalho em cubos grandes derrete só por fora e mantém textura — perfeito."}'::jsonb),
  ('carne_magra_jerimum_ensopado', 'Patinho Ensopado c/ Jerimum', '🎃', 'Almoço · Nordestino fit', '20 min', 'Patinho em cubos ensopado rápido com jerimum (abóbora) e couve — versão magra e prática no lugar da panelada.', 'nordeste', 'BA', '{"ings":[{"n":"Patinho em cubos pequenos","a":"120 g"},{"n":"Jerimum (abóbora cabotiá) em cubos","a":"150 g"},{"n":"Arroz integral cozido","a":"2 col sopa"},{"n":"Couve refogada","a":"1 xícara"},{"n":"Salada","a":"à vontade"},{"n":"Cebola, alho, tomate, colorau, cominho","a":"a gosto"}],"steps":["Tempere o patinho com alho, sal, cominho e colorau; 10 min.","Doure em panela com fio de azeite por 4 min.","Acrescente cebola, tomate e jerimum em cubos.","Cubra com 1/2 xícara de água; cozinhe 10 min até o jerimum amolecer.","Em paralelo, refogue a couve com alho.","Sirva com arroz integral e couve."],"tip":"Jerimum (cabotiá) tem textura cremosa — quando desmancha um pouco, engrossa o caldo naturalmente."}'::jsonb),
  ('sopa_feijao_verde', 'Sopa de Feijão Verde com Carne Seca', '🥣', 'Jantar · Rústico', '45 min', 'Caldo reforçado de feijão verde com carne seca desfiada por cima.', 'nordeste', 'CE', '{"ings":[{"n":"Feijão verde cozido com caldo","a":"2 xícaras"},{"n":"Carne seca dessalgada desfiada","a":"150 g"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"},{"n":"Manteiga de garrafa, pimenta","a":"a gosto"}],"steps":["Refogue a carne seca desfiada na manteiga de garrafa.","Bata metade do feijão no liquidificador com caldo.","Volte à panela; junte o feijão inteiro e mais caldo.","Cozinhe por 10 min; ajuste sal.","Sirva com a carne seca por cima e cheiro-verde."],"tip":"Feijão verde do Nordeste (não é o edamame) se chama feijão-verde-de-corda."}'::jsonb),
  ('sopa_legumes_charque', 'Sopa de Legumes com Macaxeira e Charque', '🥣', 'Jantar · Nutritiva', '40 min', 'Caldo reforçado com macaxeira, legumes e pedaços de charque.', 'nordeste', 'MA', '{"ings":[{"n":"Charque dessalgado em cubos","a":"200 g"},{"n":"Macaxeira em cubos","a":"300 g"},{"n":"Cenoura, abobrinha, chuchu","a":"2 xícaras"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"}],"steps":["Cozinhe o charque em pressão por 20 min; reserve o caldo.","Refogue cebola e alho; junte o charque.","Acrescente macaxeira, cenoura e outros legumes.","Cubra com o caldo do charque + água morna; cozinhe 15 min.","Amasse alguns pedaços de macaxeira para engrossar.","Finalize com cheiro-verde."],"tip":"Charque é mais salgado que carne seca — dessalgar em 3 águas é o mínimo."}'::jsonb),
  ('sururu_refogado', 'Sururu Refogado', '🦪', 'Almoço · Alagoano', '25 min', 'Sururu (marisco) refogado com leite de coco e dendê — ícone de Alagoas.', 'nordeste', 'AL', '{"ings":[{"n":"Sururu limpo (sem casca)","a":"300 g"},{"n":"Leite de coco","a":"150 ml"},{"n":"Azeite de dendê","a":"1 col sopa"},{"n":"Cebola, alho, coentro, tomate, pimentão","a":"a gosto"}],"steps":["Lave bem o sururu em água corrente várias vezes.","Refogue cebola e alho num fio de azeite.","Acrescente tomate e pimentão; cozinhe por 3 min.","Junte o sururu, leite de coco e dendê.","Cozinhe por 8-10 min mexendo ocasionalmente.","Finalize com coentro fresco."],"tip":"Sururu fresco tem cheiro suave de mar — cheiro forte = já estragou."}'::jsonb),
  ('cuscuz', 'Cuscuz Nordestino', '🌽', 'Café/Lanche · Nordestino', '15 min', 'Cuscuz de flocão cozido no vapor — base do café da manhã do Nordeste.', 'nordeste', 'PE', '{"ings":[{"n":"Flocão de milho","a":"1 xícara"},{"n":"Água","a":"1/2 xícara"},{"n":"Sal","a":"1 pitada"},{"n":"Manteiga (opcional)","a":"1 col ch"}],"steps":["Umedeça o flocão com a água e o sal aos poucos, mexendo com garfo.","Deixe hidratar 5 min até absorver toda água.","Transfira para cuscuzeira (ou escorredor de macarrão sobre panela com água fervente).","Cozinhe no vapor por 8-10 min.","Solte com garfo; finalize com manteiga se quiser."],"tip":"Flocão mais graúdo fica mais soltinho — flocão fino vira uma polenta úmida."}'::jsonb),
  ('macaxeira_cozida', 'Macaxeira Cozida', '🍠', 'Acompanhamento · Nordestino', '30 min', 'Macaxeira (mandioca doce) cozida simples — acompanhamento clássico do Nordeste.', 'nordeste', 'BA', '{"ings":[{"n":"Macaxeira descascada em pedaços","a":"500 g"},{"n":"Água","a":"1 l"},{"n":"Sal","a":"1 col ch"},{"n":"Manteiga ou azeite (opcional)","a":"a gosto"}],"steps":["Descasque a macaxeira e corte em pedaços de ~5cm.","Cozinhe em água com sal por 25 min até ficar macia.","Escorra e remova o fio central (duro) de cada pedaço.","Sirva quente com manteiga ou fio de azeite.","Ótima ao lado de carne de sol, peixe grelhado ou ovo."],"tip":"Se a macaxeira não estiver macia em 25 min, provavelmente é mandioca brava ou velha — descarte e troque."}'::jsonb),
  ('pacoca_carne_sol_pi', 'Paçoca de Carne-de-Sol Piauiense', '🥩', 'Almoço · Piauiense', '20 min', 'Paçoca pilada de carne-de-sol com farinha e coentro — ícone do sertão piauiense em versão fit.', 'nordeste', 'PI', '{"ings": [{"n": "Carne-de-sol dessalgada", "a": "120 g"}, {"n": "Farinha de mandioca", "a": "2 col sopa"}, {"n": "Cebola, alho, coentro", "a": "a gosto"}, {"n": "Folhas verdes", "a": "à vontade"}, {"n": "Azeite, limão, pimenta", "a": "a gosto"}], "steps": ["Dessalgue a carne em 2 trocas de água por 1h.", "Cozinhe a carne por 15 min; escorra e desfie em fios.", "No pilão, soque a carne com farinha até formar paçoca seca.", "Refogue cebola e alho em fio de azeite; junte a paçoca por 2 min.", "Finalize com coentro e limão; sirva com folhas."], "tip": "Paçoca autêntica é seca, não pastosa — no pilão, bater até virar fios quebradiços."}'::jsonb),
  ('cabidela_frango_pi', 'Frango ao Molho Pardo Piauiense', '🐔', 'Almoço · Piauiense', '25 min', 'Frango ao molho pardo (cabidela) simplificado com cacau — versão segura sem sangue.', 'nordeste', 'PI', '{"ings": [{"n": "Peito de frango em cubos", "a": "130 g"}, {"n": "Vinagre", "a": "2 col sopa"}, {"n": "Cacau em pó (escurecer molho)", "a": "1 col ch"}, {"n": "Arroz branco cozido", "a": "2 col sopa"}, {"n": "Cebola, alho, tomate, cheiro-verde", "a": "a gosto"}], "steps": ["Tempere o frango com alho, sal e vinagre; 10 min.", "Doure em fio de azeite; acrescente cebola e tomate.", "Cubra com 1/2 xícara de água + cacau em pó.", "Cozinhe 15 min até formar molho escuro.", "Finalize com cheiro-verde; sirva com arroz."], "tip": "Cacau em pó (sem açúcar) simula perfeitamente o escurecimento do sangue na cabidela tradicional."}'::jsonb),
